import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-admin-login',
  templateUrl: './admin-login.component.html',
  styleUrls: ['./admin-login.component.css']
})
export class AdminLoginComponent {
  email: string = '';
  password: string = '';
  errorMessage: string = '';
  isLoading: boolean = false;

  constructor(private authService: AuthService, private router: Router) {}

  adminLogin(): void {
    if (!this.email || !this.password) {
      this.errorMessage = 'Please fill in all fields';
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const result = this.authService.adminLogin({ email: this.email, password: this.password });

    if (result.success) {
      this.router.navigate(['/dashboard']);
    } else {
      this.errorMessage = result.message;
    }

    this.isLoading = false;
  }

  goToUserLogin(): void {
    this.router.navigate(['/login']);
  }

  validateAdmin(): boolean {
    return !!(this.email && this.password);
  }
}
<div class="admin-login-container">
  <div class="admin-login-card">
    <h2>Admin Login</h2>
    <div class="admin-badge">
      <i class="admin-icon">🔒</i>
      <span>Administrator Access</span>
    </div>
    <form (ngSubmit)="adminLogin()">
      <div class="form-group">
        <label for="email">Admin Email:</label>
        <input 
          type="email" 
          id="email" 
          name="email" 
          [(ngModel)]="email" 
          required 
          email
          placeholder="Enter admin email"
        />
      </div>

      <div class="form-group">
        <label for="password">Admin Password:</label>
        <input 
          type="password" 
          id="password" 
          name="password" 
          [(ngModel)]="password" 
          required 
          placeholder="Enter admin password"
        />
      </div>

      <div class="error-message" *ngIf="errorMessage">
        {{ errorMessage }}
      </div>

      <button type="submit" class="login-btn" [disabled]="isLoading || !validateAdmin()">
        <span *ngIf="!isLoading">Admin Login</span>
        <span *ngIf="isLoading">Authenticating...</span>
      </button>
    </form>

    <div class="login-links">
      <p>Not an admin? <a (click)="goToUserLogin()">User Login</a></p>
      <div class="demo-credentials">
        <small>Demo Credentials:</small>
        <small>Email: admin@library.com</small>
        <small>Password: admin123</small>
      </div>
    </div>
  </div>
</div>
